5	
6	#![allow(clippy::not_unsafe_ptr_arg_deref, clippy::missing_safety_doc)]
7	
8	//! TMA Copy Example (SM90+ / Hopper+)
9	//!
10	//! Demonstrates TMA (Tensor Memory Accelerator) usage:
11	//! - cp_async_bulk_tensor_2d_g2s: Async 2D tensor copy global → shared
12	//! - mbarrier: Barrier-based completion tracking
13	//!
14	//! Note: This example requires Hopper (sm_90) or newer GPUs.
15	//! For TMA multicast (sm_100a), see the `tma_multicast` example.
16	//!
17	//! Build and run with:
18	//!   cargo oxide run tma_copy
19	
20	use cuda_core::{
21	    CudaContext, CudaStream, DeviceBuffer, LaunchConfig,
22	    sys::{
23	        self as cuda_sys, CUtensorMap, CUtensorMapDataType_enum_CU_TENSOR_MAP_DATA_TYPE_FLOAT32,
24	        CUtensorMapFloatOOBfill_enum_CU_TENSOR_MAP_FLOAT_OOB_FILL_NONE,
25	        CUtensorMapInterleave_enum_CU_TENSOR_MAP_INTERLEAVE_NONE,
26	        CUtensorMapL2promotion_enum_CU_TENSOR_MAP_L2_PROMOTION_NONE,
27	        CUtensorMapSwizzle_enum_CU_TENSOR_MAP_SWIZZLE_NONE, cuTensorMapEncodeTiled,
28	    },
29	};
30	use cuda_device::barrier::{
31	    Barrier, fence_proxy_async_shared_cta, mbarrier_arrive, mbarrier_arrive_expect_tx,
32	    mbarrier_init, mbarrier_try_wait,
33	};
34	use cuda_device::tma::{TmaDescriptor, cp_async_bulk_tensor_2d_g2s};
35	use cuda_device::{DisjointSlice, SharedArray, kernel, thread};
36	use cuda_host::cuda_module;
37	use std::mem::MaybeUninit;
38	use std::sync::Arc;
39	
40	// =============================================================================
41	// KERNELS
42	// =============================================================================
43	#[cuda_module]
44	mod kernels {
45	    use super::*;
46	
47	    /// TMA 2D tile copy test kernel.
48	    ///
49	    /// Pattern: ALL threads participate in barrier
50	    /// - Thread 0: arrive_expect_tx (arrive + set expected bytes) + issue TMA
51	    /// - Other threads: regular arrive
52	    /// - ALL threads: wait on barrier
53	    #[kernel]
54	    pub fn tma_copy_2d_test(
55	        tensor_map: *const TmaDescriptor,
56	        mut out: DisjointSlice<f32>,
57	        tile_x: i32,
58	        tile_y: i32,
59	    ) {
60	        const TILE_SIZE: usize = 64 * 64;
61	        const TILE_BYTES: u32 = (TILE_SIZE * 4) as u32;
62	        // TMA destinations require 128-byte alignment
63	        static mut TILE: SharedArray<f32, TILE_SIZE, 128> = SharedArray::UNINIT;
64	        // Barriers use natural alignment (8 bytes for i64)
65	        static mut BAR: Barrier = Barrier::UNINIT;
66	
67	        let tid = thread::threadIdx_x();
68	        let block_size = thread::blockDim_x();
69	        let gid = thread::index_1d();
70	
71	        // Thread 0 initializes barrier with BLOCK SIZE (all threads will arrive)
72	        if tid == 0 {
73	            unsafe {
74	                mbarrier_init(&raw mut BAR, block_size);
75	                // CRITICAL: Fence to make barrier init visible to TMA async proxy!
76	                fence_proxy_async_shared_cta();
77	            }
78	        }
79	        thread::sync_threads();
80	
81	        // Thread 0: issue TMA + arrive with expected bytes
82	        if tid == 0 {
83	            unsafe {
84	                cp_async_bulk_tensor_2d_g2s(
85	                    &raw mut TILE as *mut u8,
86	                    tensor_map,
87	                    tile_x,
88	                    tile_y,
89	                    &raw mut BAR,
90	                );
91	            }
92	        }
93	
94	        // ALL threads arrive at barrier
95	        // Thread 0: arrive with expected TX bytes
96	        // Other threads: regular arrive
97	        let token = unsafe {
98	            if tid == 0 {
99	                mbarrier_arrive_expect_tx(&raw const BAR, 1, TILE_BYTES)
100	            } else {
101	                mbarrier_arrive(&raw const BAR)
102	            }
103	        };
104	
105	        // ALL threads wait for barrier completion (using try_wait for better scheduling)
106	        unsafe {
107	            while !mbarrier_try_wait(&raw const BAR, token) {
108	                // Hardware may briefly suspend thread while waiting
109	            }
110	        }
111	
112	        // Now TMA is complete, shared memory has the data
