433	        cuTensorMapEncodeTiled(
434	            tensor_map.as_mut_ptr(),
435	            CUtensorMapDataType_enum_CU_TENSOR_MAP_DATA_TYPE_FLOAT32,
436	            tensor_rank,
437	            global_address,
438	            global_dim.as_ptr(),
439	            global_strides.as_ptr(),
440	            box_dim.as_ptr(),
441	            element_strides.as_ptr(),
442	            CUtensorMapInterleave_enum_CU_TENSOR_MAP_INTERLEAVE_NONE,
443	            CUtensorMapSwizzle_enum_CU_TENSOR_MAP_SWIZZLE_NONE,
